#!/bin/bash

source ${HOME}/miniconda3/etc/profile.d/conda.sh
conda activate rocprofiler-compute

BASE_DIR=${HOME}/workspace/ici-workspace/ici/benchmarks/mi300x_l1_lat_multi_warp
BIN_DIR=${BASE_DIR}/bin

# set workload dir to current directory's workloads
WORKLOAD_DIR=workloads

ROCPROF_COMPUTE=/opt/rocm-6.4.1/bin/rocprof-compute

# List of all executables generated by the Makefile
TARGETS=(
  "l1_lat_coal_w_2_r_4096"
  "l1_lat_coal_w_2_r_8192"
  "l1_lat_coal_w_4_r_4096"
  "l1_lat_coal_w_4_r_8192"
  "l1_lat_coal_w_8_r_4096"
  "l1_lat_coal_w_8_r_8192"
  "l1_lat_coal_w_16_r_4096"
  "l1_lat_coal_w_16_r_8192"
)

# Loop through each target and run profiling and analysis
for TARGET in "${TARGETS[@]}"; do
  echo "Profiling and analyzing ${TARGET}..."
  $ROCPROF_COMPUTE profile -n ${TARGET} -- ${BIN_DIR}/${TARGET}
  $ROCPROF_COMPUTE analyze -p ${WORKLOAD_DIR}/${TARGET}/MI300X_A1/ -k 0 > ${WORKLOAD_DIR}/${TARGET}/MI300X_A1/analyze.out
done